import os, hashlib, difflib

def sha256_file(p):
    h = hashlib.sha256()
    with open(p, "rb") as f:
        for ch in iter(lambda: f.read(1024 * 1024), b""):
            h.update(ch)
    return h.hexdigest()

entries = []
for root, _, files in os.walk("/boot"):
    for name in sorted(files):
        p = os.path.join(root, name)
        rel = os.path.relpath(p, "/boot")
        entries.append(f"{sha256_file(p)}  {rel}\n")

baseline_list = "/root/baselines/boot.sha256list"
base_lines = open(baseline_list).read().splitlines(keepends=True)
print("".join(difflib.unified_diff(base_lines, entries, fromfile="baseline_boot_sha256list", tofile="current_boot_sha256list")))
